// Calculate staleness threshold: 180 days (6 months) ago
const now = new Date();
const threshold = new Date(now.getTime() - 180 * 24 * 60 * 60 * 1000);
const thresholdStr = threshold.toISOString();
const reportDate = now.toISOString().split('T')[0];

return [{ json: { threshold: thresholdStr, reportDate } }];

// Build staleness report from both blog posts and location pages
const staleBlogs = $('Get Stale Blog Posts').first().json.body || [];
const staleLocations = $('Get Stale Location Pages').first().json.body || [];
const reportDate = $('Calculate Staleness Threshold').first().json.reportDate;

const totalStale = staleBlogs.length + staleLocations.length;

if (totalStale === 0) {
  return [{ json: { skipEmail: true, totalStale: 0 } }];
}

// Helper to calculate days since update
function daysSince(dateStr) {
  if (!dateStr) return 'N/A';
  const d = new Date(dateStr);
  const now = new Date();
  return Math.floor((now - d) / (1000 * 60 * 60 * 24));
}

// Build blog posts table
let blogTable = '';
if (staleBlogs.length > 0) {
  let blogRows = '';
  for (let i = 0; i < staleBlogs.length; i++) {
    const b = staleBlogs[i];
    const bg = i % 2 === 0 ? '#f9f9f9' : '#ffffff';
    const days = daysSince(b.updated_at);
    const lastUpdate = b.updated_at ? new Date(b.updated_at).toISOString().split('T')[0] : 'never';
    blogRows += `<tr style="background:${bg}">
      <td style="padding:6px 8px;border:1px solid #ddd">${b.title || b.slug}</td>
      <td style="padding:6px 8px;border:1px solid #ddd">${b.category || '-'}</td>
      <td style="padding:6px 8px;border:1px solid #ddd;text-align:center">${lastUpdate}</td>
      <td style="padding:6px 8px;border:1px solid #ddd;text-align:center;color:#c00;font-weight:bold">${days} days</td>
    </tr>`;
  }
  blogTable = `
    <h3 style="color:#2d5016;margin-top:20px">Stale Blog Posts (${staleBlogs.length})</h3>
    <table style="border-collapse:collapse;width:100%;font-size:13px">
      <thead><tr style="background:#2d5016;color:#fff">
        <th style="padding:8px;border:1px solid #ddd">Title</th>
        <th style="padding:8px;border:1px solid #ddd">Category</th>
        <th style="padding:8px;border:1px solid #ddd">Last Updated</th>
        <th style="padding:8px;border:1px solid #ddd">Age</th>
      </tr></thead>
      <tbody>${blogRows}</tbody>
    </table>`;
}

// Build location pages table
let locationTable = '';
if (staleLocations.length > 0) {
  let locRows = '';
  for (let i = 0; i < staleLocations.length; i++) {
    const l = staleLocations[i];
    const bg = i % 2 === 0 ? '#f9f9f9' : '#ffffff';
    const days = daysSince(l.updated_at);
    const lastUpdate = l.updated_at ? new Date(l.updated_at).toISOString().split('T')[0] : 'never';
    const serviceLabel = (l.service_type || '').replace(/_/g, ' ');
    locRows += `<tr style="background:${bg}">
      <td style="padding:6px 8px;border:1px solid #ddd">${l.city}</td>
      <td style="padding:6px 8px;border:1px solid #ddd">${serviceLabel}</td>
      <td style="padding:6px 8px;border:1px solid #ddd">${l.status || '-'}</td>
      <td style="padding:6px 8px;border:1px solid #ddd;text-align:center">${lastUpdate}</td>
      <td style="padding:6px 8px;border:1px solid #ddd;text-align:center;color:#c00;font-weight:bold">${days} days</td>
    </tr>`;
  }
  locationTable = `
    <h3 style="color:#2d5016;margin-top:20px">Stale Location Pages (${staleLocations.length})</h3>
    <table style="border-collapse:collapse;width:100%;font-size:13px">
      <thead><tr style="background:#2d5016;color:#fff">
        <th style="padding:8px;border:1px solid #ddd">City</th>
        <th style="padding:8px;border:1px solid #ddd">Service</th>
        <th style="padding:8px;border:1px solid #ddd">Status</th>
        <th style="padding:8px;border:1px solid #ddd">Last Updated</th>
        <th style="padding:8px;border:1px solid #ddd">Age</th>
      </tr></thead>
      <tbody>${locRows}</tbody>
    </table>`;
}

const html = `
<div style="font-family:Arial,sans-serif;max-width:900px;margin:0 auto">
  <h2 style="color:#2d5016">TG-101 Content Staleness Report</h2>
  <p style="color:#666">Report date: ${reportDate} | ${totalStale} stale content items found (not updated in 6+ months)</p>
  <p>Stale content can hurt SEO rankings. Google favors fresh, regularly updated content. Consider refreshing these pages with updated information, new statistics, or seasonal relevance.</p>
  ${blogTable}
  ${locationTable}
  <h3 style="margin-top:20px;color:#2d5016">Recommended Actions</h3>
  <ul style="color:#444">
    <li>Update content with current year references and statistics</li>
    <li>Add new sections or FAQs relevant to the topic</li>
    <li>Refresh meta descriptions and title tags</li>
    <li>Add internal links to newer content</li>
    <li>Update any outdated pricing or service information</li>
  </ul>
  <p style="color:#888;font-size:12px;margin-top:16px">Threshold: content not updated in 180+ days. Generated by TG-101.</p>
</div>`;

return [{ json: {
  skipEmail: false,
  totalStale,
  to_email: 'totalguardllc@gmail.com',
  subject: `[TG-101] Content Staleness Alert - ${totalStale} Pages Need Refresh (${reportDate})`,
  html_body: html,
  workflow_name: 'TG-101',
  email_type: 'report'
}}];
